from typing import Optional, List, Iterable

import numpy as np
import pyproj
from geosat.cloud import PointCloud
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata
from geosat.psanp.abstractions.stage import Stage
from pyproj import CRS


class ReprojectionStage(Stage):
    """
    This stage reprojects a point cloud from a spatial reference system (SRS) to another
    """

    def __init__(
        self,
        input_epsg: Optional[int] = None,
        output_epsg: Optional[int] = None,
        stage_name: Optional[str] = None,
    ):
        super().__init__(stage_name)
        self.input_epsg = input_epsg
        self.output_epsg = output_epsg

    @classmethod
    def options(cls) -> List[Option]:
        return [
            Option(
                "input_epsg",
                type_cast=int,
                required=True,
                description="The EPSG of the input point cloud",
            ),
            Option(
                "output_epsg",
                type_cast=int,
                required=True,
                description="The EPSG to reproject the point cloud to",
            ),
        ]

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        if self.input_epsg is None or self.output_epsg is None:
            raise ValueError(
                "`input_epsg` and `output_epsg` must be set before executing the stage"
            )
        if cloud:
            transformer = pyproj.Transformer.from_crs(self.input_epsg, self.output_epsg)
            cloud.coords[:] = np.asarray(transformer.transform(*cloud.coords.T)).T
        cloud.metadata["srs_wkt"] = CRS.from_epsg(self.output_epsg).to_wkt()
        return (cloud,)
